import React, { useEffect, useMemo, useState } from "react";
import { Link } from "react-router-dom";
import api from "../../api/axios";

const AppointmentList = () => {
  const [appointments, setAppointments] = useState([]);
  const [statusFilter, setStatusFilter] = useState("all"); // all/scheduled/completed/cancelled
  const [loading, setLoading] = useState(false);
  const [deletingId, setDeletingId] = useState(null);

  const fetchAppointments = async () => {
    try {
      setLoading(true);
      const res = await api.get("/appointments"); // staff/admin protected
      setAppointments(res.data || []);
    } catch (err) {
      console.error("Fetch appointments failed:", err.response?.data || err.message);
      alert(err.response?.data?.message || "Failed to load appointments");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchAppointments();
  }, []);

  const filteredAppointments = useMemo(() => {
    if (statusFilter === "all") return appointments;
    return appointments.filter((a) => a.status === statusFilter);
  }, [appointments, statusFilter]);

  // ✅ DELETE appointment
  const deleteAppointment = async (id) => {
    if (!window.confirm("Delete this appointment permanently?")) return;

    try {
      setDeletingId(id);
      await api.delete(`/appointments/${id}`); // ✅ must exist in backend
      setAppointments((prev) => prev.filter((a) => a._id !== id));
      alert("Appointment deleted");
    } catch (err) {
      console.error("Delete appointment failed:", err.response?.data || err.message);

      const status = err.response?.status;
      if (status === 401) return alert("Unauthorized (401). Please login again.");
      if (status === 403) return alert("Forbidden (403). You don't have permission.");
      if (status === 404) return alert("Not found (404). Delete route not matching backend.");

      alert(err.response?.data?.message || "Failed to delete appointment");
    } finally {
      setDeletingId(null);
    }
  };

  return (
    <div style={{ padding: 20 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <h2 style={{ margin: 0 }}>Appointments</h2>

        <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
          <label style={{ fontSize: 14 }}>
            Status:
            <select
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value)}
              style={{ marginLeft: 8, padding: 6 }}
              disabled={loading}
            >
              <option value="all">All</option>
              <option value="scheduled">Scheduled</option>
              <option value="completed">Completed</option>
              <option value="cancelled">Cancelled</option>
            </select>
          </label>

          <button onClick={fetchAppointments} style={{ padding: "6px 10px" }} disabled={loading}>
            {loading ? "Loading..." : "Refresh"}
          </button>

          <Link to="/appointments/add">
            <button style={{ padding: "6px 10px" }}>+ Add Appointment</button>
          </Link>
        </div>
      </div>

      <div style={{ marginTop: 14 }}>
        <table border="1" cellPadding="10" style={{ width: "100%", textAlign: "left" }}>
          <thead>
            <tr>
              <th>Lead</th>
              <th>Vehicle</th>
              <th>Type</th>
              <th>Date</th>
              <th>Time</th>
              <th>Status</th>
              <th>Notes</th>
              <th>Customer</th>
              <th>Created By</th>
              <th style={{ width: 180 }}>Actions</th>
            </tr>
          </thead>

          <tbody>
            {loading && (
              <tr>
                <td colSpan="10">Loading...</td>
              </tr>
            )}

            {!loading &&
              filteredAppointments.map((a) => (
                <tr key={a._id}>
                  <td>{a.lead?.name || "-"}</td>

                  <td>
                    {a.vehicle?.brand
                      ? `${a.vehicle.brand} ${a.vehicle.model || a.vehicle.type || ""}`
                      : "-"}
                  </td>

                  <td>{a.appointmentType || "-"}</td>

                  <td>{a.date ? new Date(a.date).toLocaleDateString() : "-"}</td>
                  <td>{a.time || "-"}</td>
                  <td>{a.status || "-"}</td>

                  <td style={{ maxWidth: 220, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>
                    {a.notes || "-"}
                  </td>

                  <td>{a.customer?.name || a.customer?.email || (a.customer ? "Customer" : "-")}</td>
                  <td>{a.createdBy?.name || a.createdBy?.email || (a.createdBy ? "Staff" : "-")}</td>

                  <td>
                    <Link to={`/appointments/edit/${a._id}`}>
                      <button disabled={deletingId === a._id}>Edit</button>
                    </Link>

                    <button
                      onClick={() => deleteAppointment(a._id)}
                      style={{ marginLeft: 6 }}
                      disabled={deletingId === a._id}
                    >
                      {deletingId === a._id ? "Deleting..." : "Delete"}
                    </button>
                  </td>
                </tr>
              ))}

            {!loading && filteredAppointments.length === 0 && (
              <tr>
                <td colSpan="10">No appointments found</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AppointmentList;
